SELECT COUNT(DISTINCT s.pk_siape) AS quantidade_servidores FROM servidor s JOIN calc_hora_aula_media c ON s.pk_siape = c.siape WHERE LOWER(s.contrato) = LOWER('efetivos') AND LOWER(s.area_ingresso) LIKE LOWER('%engenharia civil%') AND LOWER(c.sigla_campus) = LOWER('ana') AND c.ano = 2024 AND c.semestre = 1